438	func syncWorkTreeToHeadExcludingPaths(dir, fromRev string, skipPaths []string) error {
439		// Step 1: sync the index to HEAD. This is required before checkout-index
440		// below will do anything useful, and also keeps subsequent CommitTracker
441		// calls from building stale trees.
442		//
443		// ddx-7e659c95: git read-tree requires .git/index.lock. If an operator
444		// git command (git status, git commit, etc.) holds the lock concurrently,
445		// git read-tree exits 128 with "Unable to create index.lock: File exists".
446		// Retry with exponential backoff for up to 30 s so transient operator
447		// contention does not leave the main worktree index dirty.
448		out, err := readTreeHeadWithRetry(dir)
449		if err != nil {
450			return fmt.Errorf("git read-tree HEAD: %s: %w", strings.TrimSpace(string(out)), err)
451		}
452	
453		// Step 2: compute the list of tracked files changed between the previous
454		// HEAD and the current HEAD. These are the files that the landing commit
455		// added, modified, or deleted. We only restore THESE files to avoid
456		// clobbering unrelated local modifications (agent-logs being written by
457		// the running server, beads.jsonl heartbeat updates, operator scratch).
458		if fromRev == "" {
459			// No previous HEAD known — fall back to the unsafe behaviour of
460			// read-tree only. Acceptable when the caller is a best-effort path
461			// that cannot reconstruct fromRev.
462			return nil
463		}
464		diffOut, diffErr := internalgit.Command(context.Background(), dir, "diff", "--name-only", fromRev, "HEAD").CombinedOutput()
465		if diffErr != nil {
466			// Diff failed (bad fromRev, shallow history, etc.) — leave the
467			// worktree stale rather than risk a broken checkout. The CommitTracker
468			// stale-tree bug is the prior status quo and no worse than before.
469			return nil
470		}
471		changed := strings.Fields(strings.TrimSpace(string(diffOut)))
472		if len(changed) == 0 {
473			return nil
474		}
475	
476		// Step 3: split into existing-in-HEAD (checkout-index) and
477		// deleted-in-HEAD (os.Remove) buckets. checkout-index only writes files
478		// that are in the index; it cannot represent a deletion, so we handle
479		// those ourselves.
480		skip := map[string]bool{}
481		for _, path := range skipPaths {
482			skip[filepath.ToSlash(path)] = true
483		}
484		var indexFiles []string
485		var removedFiles []string
486		for _, f := range changed {
487			if skip[filepath.ToSlash(f)] {
488				continue
489			}
490			probe := internalgit.Command(context.Background(), dir, "ls-files", "--error-unmatch", "--", f)
491			if probe.Run() == nil {
492				indexFiles = append(indexFiles, f)
493			} else {
494				removedFiles = append(removedFiles, f)
495			}
496		}

497	
498		// Step 4: materialize the index-present files into the working tree.
499		// -f overwrites any stale content at these exact paths. Unrelated files
500		// are untouched because we pass the specific path list.
501		if len(indexFiles) > 0 {
502			for _, f := range indexFiles {
503				if err := os.MkdirAll(filepath.Dir(filepath.Join(dir, f)), 0o755); err != nil {
504					return fmt.Errorf("creating checkout parent for %s: %w", f, err)
505				}
506			}
507			args := []string{"checkout-index", "-f", "--"}
508			args = append(args, indexFiles...)
509			out2, err2 := internalgit.Command(context.Background(), dir, args...).CombinedOutput()
510			if err2 != nil {
511				return fmt.Errorf("git checkout-index -f: %s: %w", strings.TrimSpace(string(out2)), err2)
512			}
513		}
514	
515		// Step 5: remove files that the landing commit deleted and whose removal
516		// did not propagate to the worktree because update-ref bypassed the
517		// working-tree update.
518		for _, f := range removedFiles {
519			full := filepath.Join(dir, f)
520			_ = os.Remove(full) // best-effort; leave the file if removal fails
521		}
522	
523		return nil
524	}
