539	func ensureLandingWorktreeReady(dir, targetBranch string) error {
540		if !isInsideGitWorktree(dir) {
541			return nil
542		}
543		branchOut, err := internalgit.Command(context.Background(), dir, "branch", "--show-current").CombinedOutput()
544		if err != nil {
545			return fmt.Errorf("checking landing branch: %s: %w", strings.TrimSpace(string(branchOut)), err)
546		}
547		branch := strings.TrimSpace(string(branchOut))
548		if branch == "" {
549			return fmt.Errorf("landing worktree is detached; expected branch %q", targetBranch)
550		}
551		if targetBranch != "" && branch != targetBranch {
552			return fmt.Errorf("landing branch mismatch: on %q, want %q", branch, targetBranch)
553		}
554		return waitForEmptyGitIndex(dir, 2*time.Second)
555	}
556	
557	func isInsideGitWorktree(dir string) bool {
558		out, err := internalgit.Command(context.Background(), dir, "rev-parse", "--is-inside-work-tree").CombinedOutput()
559		return err == nil && strings.TrimSpace(string(out)) == "true"
560	}
561	
562	func waitForEmptyGitIndex(dir string, timeout time.Duration) error {
563		deadline := time.Now().Add(timeout)
564		for {
565			if err := internalgit.Command(context.Background(), dir, "diff", "--cached", "--quiet").Run(); err == nil {
566				return nil
567			}
568			if time.Now().After(deadline) {
569				stagedOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-status").CombinedOutput()
570				staged := strings.TrimSpace(string(stagedOut))
571				if staged == "" {
572					staged = "unknown staged changes"
573				}
574				return fmt.Errorf("landing worktree has staged changes after waiting %s:\n%s", timeout, staged)
575			}
576			time.Sleep(100 * time.Millisecond)
577		}
578	}
