695	func (RealLandingGitOps) CountCommits(dir, base, tip string) int {
696		out, err := internalgit.Command(context.Background(), dir, "rev-list", "--count", base+".."+tip).CombinedOutput()
697		if err != nil {
698			return 0
699		}
700		s := strings.TrimSpace(string(out))
701		n := 0
702		for _, c := range s {
703			if c >= '0' && c <= '9' {
704				n = n*10 + int(c-'0')
705			}
706		}
707		return n
708	}
