847	// landIterationRef returns the documented hidden ref for a land-time preserve.
848	// Format: refs/ddx/iterations/<bead-id>/<attempt-id>-<short-tip>. The short-tip
849	// captures the current target tip at the time of the conflict so subsequent
850	// recovery tools can reconstruct which merge target was in play.
851	func landIterationRef(beadID, attemptID, tip string) string {
852		short := tip
853		if len(short) > 12 {
854			short = short[:12]
855		}
856		attempt := attemptID
857		if attempt == "" {
858			attempt = NowFunc().UTC().Format("20060102T150405Z")
859		}
860		return fmt.Sprintf("refs/ddx/iterations/%s/%s-%s", beadID, attempt, short)
861	}
