981	func cleanupProjectEvidenceCopy(projectRoot, relPath string) {
982		cleanRel, ok := cleanRelativePath(relPath)
983		if !ok {
984			return
985		}
986		evidenceRoot := filepath.Join(projectRoot, cleanRel)
987		embeddedDir := filepath.Join(evidenceRoot, "embedded")
988		if info, err := os.Stat(embeddedDir); err == nil && info.IsDir() {
989			entries, err := os.ReadDir(evidenceRoot)
990			if err != nil {
991				return
992			}
993			for _, entry := range entries {
994				if entry.Name() == "embedded" {
995					continue
996				}
997				_ = os.RemoveAll(filepath.Join(evidenceRoot, entry.Name()))
998			}
999			return
1000		}
1001		_ = os.RemoveAll(evidenceRoot)
1002	}
