1004	func cleanRelativePath(path string) (string, bool) {
1005		if path == "" || filepath.IsAbs(path) {
1006			return "", false
1007		}
1008		clean := filepath.Clean(filepath.FromSlash(path))
1009		if clean == "." || strings.HasPrefix(clean, ".."+string(os.PathSeparator)) || clean == ".." {
1010			return "", false
1011		}
1012		return clean, true
1013	}
