1036	// Land performs fetch → (ff or merge) → push for a single submission.
1037	// It serializes primary-checkout git operations with the process-shared
1038	// main-git lock so separate ddx work processes cannot interleave landing with
1039	// tracker commits or pre-dispatch checkpoint/ref updates.
1040	//
1041	// projectRoot is the directory containing the project's .git. req.WorktreeDir,
1042	// when non-empty, is used as the git working directory for all commands; when
1043	// empty, projectRoot is used. Both usually refer to the same dir — the field
1044	// is kept for forward compatibility with multi-clone topologies.
1045	func Land(projectRoot string, req LandRequest, gitOps LandingGitOps) (*LandResult, error) {
1046		var result *LandResult
1047		err := withMainGitLock(projectRoot, func() error {
1048			var landErr error
1049			result, landErr = landLocked(projectRoot, req, gitOps)
1050			return landErr
1051		})
1052		return result, err
1053	}
1054	
1055	func landLocked(projectRoot string, req LandRequest, gitOps LandingGitOps) (*LandResult, error) {
1056		if gitOps == nil {
1057			gitOps = RealLandingGitOps{}
1058		}
1059		wd := req.WorktreeDir
1060		if wd == "" {
1061			wd = projectRoot
1062		}
1063	
1064		// Trivial guard — no commits to land.
1065		if req.ResultRev == "" || req.ResultRev == req.BaseRev {
1066			return &LandResult{Status: "no-changes", Reason: "result_rev == base_rev"}, nil
1067		}
1068		syncOperatorAfterLand := sameFilesystemPath(projectRoot, wd)
1069		var operatorDirtyBeforeLand []string
1070		if syncOperatorAfterLand {
1071			operatorDirtyBeforeLand = dirtyWorktreePaths(wd)
1072		}
1073	
1074		// Resolve target branch (default to project HEAD).
1075		targetBranch := req.TargetBranch
1076		if targetBranch == "" {
1077			br, err := gitOps.CurrentBranch(wd)
1078			if err != nil {
1079				return nil, fmt.Errorf("resolving target branch: %w", err)
1080			}
1081			targetBranch = br
1082		}
1083		if err := ensureLandingWorktreeReady(wd, targetBranch); err != nil {
1084			return nil, err
1085		}
1086		targetRef := "refs/heads/" + targetBranch
1087	
1088		// Fetch the current target tip from origin when available; otherwise
1089		// read the local branch directly.
1090		hasOrigin := gitOps.HasRemote(wd, "origin")
1091		if hasOrigin {
1092			// Fetch is best-effort: a disconnected remote must not block
1093			// a local land. Log-style errors are swallowed here; the
1094			// subsequent ResolveRef will surface any fatal issue.
1095			_ = gitOps.FetchBranch(wd, "origin", targetBranch)
1096		}

1097		currentTip, err := gitOps.ResolveRef(wd, targetRef)
1098		if err != nil {
1099			return nil, fmt.Errorf("resolving target tip %s: %w", targetRef, err)
1100		}
1101	
1102		contribCount := gitOps.CountCommits(wd, req.BaseRev, req.ResultRev)
1103	
1104		if preserved, err := preserveIfLargeDeletion(wd, req, gitOps, currentTip, contribCount); err != nil {
1105			return nil, err
1106		} else if preserved != nil {
1107			return preserved, nil
1108		}
1109		if preserved, err := preserveIfSyntaxSanityFails(wd, req, gitOps, currentTip, contribCount); err != nil {
1110			return nil, err
1111		} else if preserved != nil {
1112			return preserved, nil
1113		}
1114	
1115		// Fast path: no sibling advanced the target branch → straight ff via
1116		// update-ref. The worker's commit becomes the new tip unchanged; its
1117		// parent is still BaseRev, so replay sees the same inputs the worker
1118		// saw. No merge commit is created.
1119		if currentTip == req.BaseRev {
1120			if err := gitOps.UpdateRefTo(wd, targetRef, req.ResultRev, currentTip); err != nil {
1121				return nil, fmt.Errorf("fast-forwarding %s to %s: %w", targetRef, req.ResultRev, err)
1122			}
1123			result := &LandResult{
1124				Status:            "landed",
1125				NewTip:            req.ResultRev,
1126				Merged:            false,
1127				MergedCommitCount: contribCount,
1128			}
1129			finalWD, cleanup, err := landingFinalizationWorktree(projectRoot, wd, targetBranch, gitOps)
1130			if err != nil {
1131				return nil, err
1132			}
1133			defer cleanup()
1134			if preserved, err := preserveIfPostLandGateFails(finalWD, req, gitOps, targetRef, currentTip, result.NewTip, contribCount, nil); err != nil {
1135				return nil, err
1136			} else if preserved != nil {
1137				return preserved, nil
1138			}
1139			if req.EvidenceDir != "" {
1140				if err := copyEvidenceDirForLanding(projectRoot, finalWD, req.EvidenceDir); err != nil {
1141					return nil, fmt.Errorf("copying evidence into landing worktree: %w", err)
1142				}
1143				if err := landEvidence(finalWD, targetBranch, req, gitOps, result); err != nil {
1144					return preserveAfterEvidenceFailure(finalWD, req, gitOps, targetRef, currentTip, result.NewTip, contribCount, nil, err)
1145				}
1146				cleanupProjectEvidenceCopy(projectRoot, req.EvidenceDir)
1147			}
1148			landPush(finalWD, targetBranch, result.NewTip, hasOrigin, gitOps, result)
1149			if syncOperatorAfterLand {
1150				syncWorkTreeToHeadGuarded(gitOps, wd, currentTip, operatorDirtyBeforeLand, result)
1151			}
1152			return result, nil
1153		}
1154	
1155		// Merge path: the target has advanced since the worker started. Create
1156		// a temp detached worktree at currentTip and run `git merge --no-ff
1157		// ResultRev` inside it. The result is a merge commit whose parents are
1158		// [currentTip, ResultRev]. Crucially, ResultRev itself is NOT rewritten:
1159		// its parent is still BaseRev, so replay observes the original inputs.
1160		tempWT, tempWtErr := os.MkdirTemp("", "ddx-land-wt-*")
1161		if tempWtErr != nil {
1162			return nil, fmt.Errorf("creating temp worktree dir: %w", tempWtErr)
1163		}
1164		// os.MkdirTemp creates the dir, but git worktree add refuses to run if
1165		// the target already exists. Remove it first so git can recreate it.
1166		_ = os.RemoveAll(tempWT)
1167		if err := gitOps.AddWorktree(wd, tempWT, currentTip); err != nil {
1168			return nil, fmt.Errorf("adding temp worktree at %s: %w", currentTip, err)
1169		}
1170		defer func() { _ = gitOps.RemoveWorktree(wd, tempWT) }()
1171	
1172		mergeMsg := fmt.Sprintf("Merge bead %s attempt %s into %s", req.BeadID, shortAttempt(req.AttemptID), targetBranch)
1173		if err := gitOps.MergeInto(tempWT, req.ResultRev, mergeMsg); err != nil {
1174			// Merge conflict: preserve the original ResultRev and return.
1175			preserveRef := landIterationRef(req.BeadID, req.AttemptID, currentTip)
1176			if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
1177				return nil, fmt.Errorf("preserving %s after merge conflict: %w", preserveRef, upErr)
1178			}
1179			return &LandResult{
1180				Status:            "preserved",
1181				PreserveRef:       preserveRef,
1182				Reason:            "merge conflict",
1183				MergedCommitCount: contribCount,
1184			}, nil
1185		}
1186	
1187		// Merge clean: read the merge commit SHA from the temp worktree's HEAD
1188		// and fast-forward the target branch to it.
1189		mergeSHA, err := gitOps.HeadRevAt(tempWT)
1190		if err != nil {
1191			return nil, fmt.Errorf("reading merge HEAD: %w", err)
1192		}
1193		if err := gitOps.UpdateRefTo(wd, targetRef, mergeSHA, currentTip); err != nil {
1194			return nil, fmt.Errorf("fast-forwarding %s to merge commit %s: %w", targetRef, mergeSHA, err)
1195		}
1196		result := &LandResult{
1197			Status:            "landed",
1198			NewTip:            mergeSHA,
1199			Merged:            true,
1200			MergedCommitCount: contribCount,
1201		}
1202		finalWD, cleanup, err := landingFinalizationWorktree(projectRoot, wd, targetBranch, gitOps)
1203		if err != nil {
1204			return nil, err
1205		}
1206		defer cleanup()
1207		if preserved, err := preserveIfPostLandGateFails(finalWD, req, gitOps, targetRef, currentTip, result.NewTip, contribCount, nil); err != nil {
1208			return nil, err
1209		} else if preserved != nil {
1210			return preserved, nil
1211		}
1212		if req.EvidenceDir != "" {
1213			if err := copyEvidenceDirForLanding(projectRoot, finalWD, req.EvidenceDir); err != nil {
1214				return nil, fmt.Errorf("copying evidence into landing worktree: %w", err)
1215			}
1216			if err := landEvidence(finalWD, targetBranch, req, gitOps, result); err != nil {
1217				return preserveAfterEvidenceFailure(finalWD, req, gitOps, targetRef, currentTip, result.NewTip, contribCount, nil, err)
1218			}
1219			cleanupProjectEvidenceCopy(projectRoot, req.EvidenceDir)
1220		}
1221		landPush(finalWD, targetBranch, result.NewTip, hasOrigin, gitOps, result)
1222		if syncOperatorAfterLand {
1223			syncWorkTreeToHeadGuarded(gitOps, wd, currentTip, operatorDirtyBeforeLand, result)
1224		}
1225		return result, nil
1226	}
1227	
1228	func preserveIfPostLandGateFails(wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, contribCount int, dirtyBefore []string) (*LandResult, error) {
1229		if len(req.PostLandCommand) == 0 {
1230			return nil, nil
1231		}
1232		output, err := runPostLandCommand(wd, req.PostLandCommand)
1233		if err == nil {
1234			return nil, nil
1235		}
1236	
1237		preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
1238		if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
1239			return nil, fmt.Errorf("preserving %s after post-land gate: %w", preserveRef, upErr)
1240		}
1241		if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
1242			return nil, fmt.Errorf("restoring %s to %s after post-land gate failed: %w", targetRef, preLandTip, revertErr)
1243		}
1244	
1245		reason := fmt.Sprintf("post-land gate failed: %s: %v", strings.Join(req.PostLandCommand, " "), err)
1246		if trimmed := strings.TrimSpace(output); trimmed != "" {
1247			reason += ": " + truncatePostLandGateOutput(trimmed)
1248		}
1249		result := &LandResult{
1250			Status:            "preserved",
1251			PreserveRef:       preserveRef,
1252			Reason:            reason,
1253			MergedCommitCount: contribCount,
1254		}
1255		syncWorkTreeToHeadGuarded(gitOps, wd, landedTip, dirtyBefore, result)
1256		return result, nil
1257	}
1258	
1259	func preserveAfterEvidenceFailure(wd string, req LandRequest, gitOps LandingGitOps, targetRef, preLandTip, landedTip string, contribCount int, dirtyBefore []string, evidenceErr error) (*LandResult, error) {
1260		preserveRef := landIterationRef(req.BeadID, req.AttemptID, preLandTip)
1261		if upErr := gitOps.UpdateRefTo(wd, preserveRef, req.ResultRev, ""); upErr != nil {
1262			return nil, fmt.Errorf("preserving %s after evidence commit failure: %w", preserveRef, upErr)
1263		}
1264		if landedTip != "" {
1265			if revertErr := gitOps.UpdateRefTo(wd, targetRef, preLandTip, landedTip); revertErr != nil {
1266				return nil, fmt.Errorf("restoring %s to %s after evidence commit failed: %w", targetRef, preLandTip, revertErr)
1267			}
1268		}
1269		result := &LandResult{
1270			Status:            "preserved",
1271			PreserveRef:       preserveRef,
1272			Reason:            "evidence commit failed: " + evidenceErr.Error(),
1273			MergedCommitCount: contribCount,
1274		}
1275		syncWorkTreeToHeadGuarded(gitOps, wd, landedTip, dirtyBefore, result)
1276		return result, nil
1277	}
1278	
1279	func runPostLandCommand(wd string, command []string) (string, error) {
1280		if len(command) == 0 {
1281			return "", nil
1282		}
1283		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Minute)
1284		defer cancel()
1285		cmd := exec.CommandContext(ctx, command[0], command[1:]...)
1286		cmd.Dir = wd
1287		out, err := cmd.CombinedOutput()
1288		if ctx.Err() == context.DeadlineExceeded {
1289			return string(out), ctx.Err()
1290		}
1291		return string(out), err
1292	}
1293	
1294	func truncatePostLandGateOutput(output string) string {
1295		const max = 2048
1296		if len(output) <= max {
1297			return output
1298		}
1299		return output[:max] + "...(truncated)"
1300	}
