1523	func isPushAutoMergeConflict(err error) bool {
1524		for err != nil {
1525			if _, ok := err.(*landPushAutoMergeConflictError); ok {
1526				return true
1527			}
1528			type unwrapper interface{ Unwrap() error }
1529			u, ok := err.(unwrapper)
1530			if !ok {
1531				return false
1532			}
1533			err = u.Unwrap()
1534		}
1535		return false
1536	}
