1538	// landPushAutoRecover attempts one fetch + merge + retry-push pass after the
1539	// initial push was rejected. Returns recovered=true and the new merge SHA
1540	// when the retry-push succeeds; otherwise returns recovered=false plus an
1541	// error that indicates whether the recovery hit a merge conflict (wrapped in
1542	// landPushAutoMergeConflictError) or some other failure.
1543	//
1544	// Caller responsibilities (already met by landPush):
1545	//   - The local target ref is at newTip and not yet pushed.
1546	//   - hasOrigin is true.
1547	func landPushAutoRecover(wd, targetBranch, newTip string, gitOps LandingGitOps) (recovered bool, mergeSHA string, err error) {
1548		dirtyBefore := dirtyWorktreePaths(wd)
1549		if fetchErr := gitOps.FetchBranch(wd, "origin", targetBranch); fetchErr != nil {
1550			return false, "", fmt.Errorf("auto-recovery fetch origin %s: %w", targetBranch, fetchErr)
1551		}
1552		originSHA, resolveErr := gitOps.ResolveRef(wd, "refs/remotes/origin/"+targetBranch)
1553		if resolveErr != nil {
1554			return false, "", fmt.Errorf("auto-recovery resolve origin/%s: %w", targetBranch, resolveErr)
1555		}
1556		if originSHA == newTip {
1557			// Origin is already at our tip — push must have failed for a reason
1558			// other than a non-fast-forward (auth, branch protection, large
1559			// blob, etc.). Recovery cannot help.
1560			return false, "", fmt.Errorf("origin already at local tip; push failure not recoverable by auto-merge")
1561		}
1562		tempWT, mkErr := os.MkdirTemp("", "ddx-push-recover-*")
1563		if mkErr != nil {
1564			return false, "", fmt.Errorf("auto-recovery temp worktree: %w", mkErr)
1565		}
1566		_ = os.RemoveAll(tempWT)
1567		if addErr := gitOps.AddWorktree(wd, tempWT, originSHA); addErr != nil {
1568			return false, "", fmt.Errorf("auto-recovery add worktree at %s: %w", originSHA, addErr)
1569		}
1570		defer func() { _ = gitOps.RemoveWorktree(wd, tempWT) }()
1571	
1572		mergeMsg := fmt.Sprintf("Merge origin/%s into %s after push race", targetBranch, targetBranch)
1573		if mergeErr := gitOps.MergeInto(tempWT, newTip, mergeMsg); mergeErr != nil {
1574			return false, "", &landPushAutoMergeConflictError{inner: mergeErr}
1575		}
1576		mergeSHA, headErr := gitOps.HeadRevAt(tempWT)
1577		if headErr != nil {
1578			return false, "", fmt.Errorf("auto-recovery read merge HEAD: %w", headErr)
1579		}
1580		targetRef := "refs/heads/" + targetBranch
1581		if updErr := gitOps.UpdateRefTo(wd, targetRef, mergeSHA, newTip); updErr != nil {
1582			return false, "", fmt.Errorf("auto-recovery advance %s to %s: %w", targetRef, mergeSHA, updErr)
1583		}
1584		syncWorkTreeToHeadGuarded(gitOps, wd, newTip, dirtyBefore, nil)
1585		if pushErr := gitOps.PushFFOnly(wd, "origin", mergeSHA, targetBranch); pushErr != nil {
1586			return false, "", fmt.Errorf("auto-recovery retry push: %w", pushErr)
1587		}
1588		return true, mergeSHA, nil
1589	}
