// TestLand_IsNetworkFree is compile-time + runtime proof that Land() performs no
// network I/O. noNetworkGitOps implements LandingGitOps without FetchBranch,
// PushFFOnly, or FetchOriginAncestryCheck methods; if Land() tried to call any of
// those it would not compile because they are not in the interface. The test then
// asserts that Land() succeeds end-to-end on the fast-forward path.
func TestLand_IsNetworkFree(t *testing.T) {
	r := newLandTestRepo(t)

	workerSHA := r.commitOn(r.baseSHA, "feat.txt", "feature\n", "feat: add feature")

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-netfree",
		AttemptID:    "20260511T000001-nf",
		TargetBranch: "main",
	}

	// noNetworkGitOps delegates to RealLandingGitOps for all local operations
	// but does NOT implement FetchBranch, PushFFOnly, or FetchOriginAncestryCheck.
	// This is the compile-time proof: if Land() called any of those methods via
	// the LandingGitOps interface, this struct would fail to satisfy the interface
	// and the test would not compile.
	var ops LandingGitOps = noNetworkGitOps{}

	land, err := Land(r.dir, req, ops)
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected status=landed, got %q (reason=%q)", land.Status, land.Reason)
	}
	if got := r.resolveRef("refs/heads/main"); got != workerSHA {
		t.Errorf("local main tip = %s, want %s", got, workerSHA)
	}
}

// noNetworkGitOps implements LandingGitOps using only local git operations.
// It has no FetchBranch, PushFFOnly, or FetchOriginAncestryCheck methods,
// providing compile-time proof that Land() does not call them.
type noNetworkGitOps struct{}

func (noNetworkGitOps) CurrentBranch(dir string) (string, error) {
	return RealLandingGitOps{}.CurrentBranch(dir)
}
func (noNetworkGitOps) ResolveRef(dir, ref string) (string, error) {
	return RealLandingGitOps{}.ResolveRef(dir, ref)
}
func (noNetworkGitOps) UpdateRefTo(dir, ref, sha, oldSHA string) error {
	return RealLandingGitOps{}.UpdateRefTo(dir, ref, sha, oldSHA)
