// TestLand_LockReleasedBeforeLandReturn asserts that withMainGitLock is released
// before Land() returns — i.e. no post-land work (like a push) is performed
// inside the lock. The test records the lock hold time via TrackerLockMetricsSink
// and fails if it exceeds 1s, which proves no network I/O (which would take 5-120s
// in a real deployment) is included inside the critical section.
func TestLand_LockReleasedBeforeLandReturn(t *testing.T) {
	r := newLandTestRepo(t)

	workerSHA := r.commitOn(r.baseSHA, "feat2.txt", "data\n", "feat: lock-timing test")

	var lockHold time.Duration
	old := TrackerLockMetricsSink
	TrackerLockMetricsSink = func(s TrackerLockSample) {
		lockHold = s.Hold
	}
	defer func() { TrackerLockMetricsSink = old }()

	req := LandRequest{
		WorktreeDir:  r.dir,
		BaseRev:      r.baseSHA,
		ResultRev:    workerSHA,
		BeadID:       "ddx-land-locktime",
		AttemptID:    "20260511T000002-lt",
		TargetBranch: "main",
	}
	land, err := Land(r.dir, req, noNetworkGitOps{})
	if err != nil {
		t.Fatalf("Land: %v", err)
	}
	if land.Status != "landed" {
		t.Fatalf("expected status=landed, got %q", land.Status)
	}

	// Simulate 5s of post-Land work in the caller (e.g. a push) without
	// holding the lock. We don't actually sleep 5s; we just verify the lock
	// was not held for anywhere near that long.
	const lockHoldBudget = time.Second
	if lockHold >= lockHoldBudget {
		t.Errorf("withMainGitLock held for %s — expected < %s (no network I/O inside lock)", lockHold, lockHoldBudget)
	}
}

